    [InlineData("ABC", 3)]
    [InlineData("ABCDEFGHIJ", 10)]
    public void WFiltro_LigarPara_WithDifferentLengths_ShouldAddParameter(string value, int expectedLength)
    {
        // Arrange
        var filtro = new FilterLigacoes
        {
            LigarPara = value,
            WildcardChar = '%',
            LogicalOperator = TSql.And
        };
        // Act
        var result = _serviceS.WFiltroLigacoes(filtro);
        // Assert
        result.Should().NotBeNull();
        result.Value.parametros.Should().HaveCount(1);
        var param = result.Value.parametros.First();
        // Value should be %value% so length is value.Length + 2
        param?.Value?.ToString()?.Length.Should().Be(expectedLength + 1);
    }

